input.content:
# PROG_IO_MAP VAR_EXTERNAL CSV generator
# 320 variables: 160 input (_xx_INxx) + 160 output (_xx_OUTxx)
# Encoding: EUC-KR (CP949) + CRLF

$csvPath = "$PSScriptRoot\ST_UPDATE\PROG_IO_MAP_VARS.csv"
$exampleCsv = "$PSScriptRoot\example.csv"

# Read example CSV header (EUC-KR)
$headerBytes = $null
if (Test-Path $exampleCsv) {
    $allBytes = [System.IO.File]::ReadAllBytes($exampleCsv)
    # Find first CRLF to get header line
    for ($i = 0; $i -lt $allBytes.Length - 1; $i++) {
        if ($allBytes[$i] -eq 0x0D -and $allBytes[$i+1] -eq 0x0A) {
            $headerBytes = $allBytes[0..($i+1)]
            break
        }
    }
}

if ($null -eq $headerBytes) {
    # Fallback: create header manually in EUC-KR
    $enc = [System.Text.Encoding]::GetEncoding(949)
    $header = "변수 종류,변수,타입,메모리 할당,초기값,리테인,사용 유무,EIP,OPC UA,HMI,모션,설명문"
    $headerBytes = $enc.GetBytes($header) + @(0x0D, 0x0A)
}

$lines = New-Object System.Collections.ArrayList
$crlf = @(0x0D, 0x0A)

# Input slots: 0,1,2,3,4 (each 32 bits = IN00~IN31)
$inputSlots = @(0, 1, 2, 3, 4)
foreach ($slot in $inputSlots) {
    $slotStr = "{0:D2}" -f $slot
    for ($bit = 0; $bit -lt 32; $bit++) {
        $bitStr = "{0:D2}" -f $bit
        $varName = "_{0}_IN{1}" -f $slotStr, $bitStr
        $line = "VAR_EXTERNAL,$varName,BOOL,,,,TRUE,,,,,"
        [void]$lines.Add($line)
    }
}

# Output slots: 0,5,6,7,8 (each 32 bits = OUT00~OUT31)
$outputSlots = @(0, 5, 6, 7, 8)
foreach ($slot in $outputSlots) {
    $slotStr = "{0:D2}" -f $slot
    for ($bit = 0; $bit -lt 32; $bit++) {
        $bitStr = "{0:D2}" -f $bit
        $varName = "_{0}_OUT{1}" -f $slotStr, $bitStr
        $line = "VAR_EXTERNAL,$varName,BOOL,,,,TRUE,,,,,"
        [void]$lines.Add($line)
    }
}

# Build output bytes
$output = New-Object System.Collections.ArrayList
[void]$output.AddRange($headerBytes)

$ascii = [System.Text.Encoding]::ASCII
foreach ($line in $lines) {
    $lineBytes = $ascii.GetBytes($line)
    [void]$output.AddRange($lineBytes)
    [void]$output.AddRange($crlf)
}

[System.IO.File]::WriteAllBytes($csvPath, [byte[]]$output.ToArray())

Write-Host "Generated: $csvPath"
Write-Host "Total variables: $($lines.Count) (Input: $($inputSlots.Count * 32), Output: $($outputSlots.Count * 32))"

